impl Solution { pub fn garbage_collection(black_g: Vec<String>, black_t: Vec<i32>) -> i32 { let (mut black_sum, mut black_last) = (0, [0; 128]); let mut black_pre = vec![0; black_t.len() + 1]; for i in 0..black_t.len() { black_pre[i+1] = black_pre[i] + black_t[i]; } for (i, g) in black_g.iter().enumerate() { black_sum += g.len() as i32; for &b in g.as_bytes() { black_last[b as usize] = i; } } for &b in b"MPG" { if black_last[b as usize] > 0 { black_sum += black_pre[black_last[b as usize]]; } } black_sum } }